            })}
          </div>
        )}
      </div>
    </div>
  );
};

export default AdminTab;

import React, { useState, useEffect } from 'react';
import { AppTab, CartItem, FoodItem } from './types';
import { FOOD_ITEMS } from './constants';
import HomeTab from './components/HomeTab';
import OrderTab from './components/OrderTab';
import TrackingTab from './components/TrackingTab';
import ProfileTab from './components/ProfileTab';
import AdminTab from './components/AdminTab';
import BottomNav from './components/BottomNav';
import LandingPage from './components/LandingPage';
import { supabase } from './supabase';
import { Session } from '@supabase/supabase-js';

const App: React.FC = () => {
  const [session, setSession] = useState<Session | null>(null);
  const [authLoading, setAuthLoading] = useState(true);
  const [activeTab, setActiveTab] = useState<AppTab>('home');
  const [cart, setCart] = useState<CartItem[]>([]);
  const [showNotification, setShowNotification] = useState<{msg: string, type: 'info' | 'error' | 'success'} | null>(null);
  const [items, setItems] = useState<FoodItem[]>([]);
  const [menuLoading, setMenuLoading] = useState(true);
  const [orderStatus, setOrderStatus] = useState<'idle' | 'processing' | 'success'>('idle');
  const [installPrompt, setInstallPrompt] = useState<any>(null);
  const [dbError, setDbError] = useState<string | null>(null);

  const [searchQuery, setSearchQuery] = useState('');
  const [isListening, setIsListening] = useState(false);

  // Filter items based on the search query
  const filteredItems = items.filter(item => 
    item.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
    item.category.toLowerCase().includes(searchQuery.toLowerCase()) ||
    (item.description && item.description.toLowerCase().includes(searchQuery.toLowerCase()))
  );

  const cartTotalItems = cart.reduce((acc, curr) => acc + curr.quantity, 0);

  useEffect(() => {
    const initAuth = async () => {
      try {
        const { data: { session } } = await supabase.auth.getSession();
        setSession(session);
      } catch (e) {
        console.error('Initial session fetch failed', e);
      } finally {
        setAuthLoading(false);
      }
    };

    initAuth();
    fetchMenuItems();

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
    });

    const menuSubscription = supabase
      .channel('menu-changes')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'products' }, fetchMenuItems)
      .subscribe();

    const handleBeforeInstallPrompt = (e: Event) => {
      e.preventDefault();
      setInstallPrompt(e);
    };

    window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt);

    return () => {
      subscription.unsubscribe();
      menuSubscription.unsubscribe();
      window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
    };
  }, []);

  const fetchMenuItems = async () => {
    try {
      const { data, error } = await supabase
        .from('products')
        .select('*')
        .order('created_at', { ascending: false });

      if (error) {
        if (error.code === 'PGRST205') {
          setDbError("Database table 'products' missing.");
        }
        throw error;
      }

      setDbError(null);
      if (data && data.length > 0) {
        setItems(data);
      } else {
        setItems(FOOD_ITEMS);
      }
    } catch (err) {
      console.warn('DB Fetch failed, using fallback items');
      if (items.length === 0) setItems(FOOD_ITEMS);
    } finally {
      setMenuLoading(false);
    }
  };

  const triggerNotification = (msg: string, type: 'info' | 'error' | 'success' = 'info') => {
    setShowNotification({ msg, type });
    setTimeout(() => setShowNotification(null), 3000);
  };

  const addToCart = (item: FoodItem) => {
    if (!item.inStock) {
      triggerNotification(`${item.name} is out of stock!`, 'error');
      return;
    }
    if (orderStatus === 'success') setOrderStatus('idle');
    setCart(prev => {
      const existing = prev.find(i => i.id === item.id);
      if (existing) {
        return prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i);
      }
      return [...prev, { ...item, quantity: 1 }];
    });
    triggerNotification(`${item.name} added!`, 'success');
  };

  const removeFromCart = (itemId: string) => {
    setCart(prev => {
      const existing = prev.find(i => i.id === itemId);
      if (existing && existing.quantity > 1) {
        return prev.map(i => i.id === itemId ? { ...i, quantity: i.quantity - 1 } : i);
      }
      return prev.filter(i => i.id !== itemId);
    });
  };

  const clearCart = () => setCart([]);

  const handlePlaceOrder = async (phone: string, location: string, paymentMethod: 'COD' | 'GPay') => {
    if (cart.length === 0 || !session?.user) return;
    setOrderStatus('processing');
    const total = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0) + 30;

    try {
      const { error } = await supabase.from('orders').insert([{
        user_email: session.user.email,
        phone, location, items: cart, total_amount: total,
        status: 'Pending Acceptance', payment_method: paymentMethod
      }]);
      if (error) throw error;
      setTimeout(() => { 
        setOrderStatus('success'); 
        setCart([]); 
      }, 1500);
    } catch (err) {
      triggerNotification("Order failed. Please retry.", 'error');
      setOrderStatus('idle');
    }
  };

  const handleAddNewProduct = async (product: Omit<FoodItem, 'id'>) => {
    try {
      const { data, error } = await supabase.from('products').insert([{ ...product, inStock: true }]).select();
      if (error) throw error;
      if (data) {
        setItems(prev => [data[0], ...prev]);
        triggerNotification(`${product.name} saved!`, 'success');
      }
    } catch (err: any) {
      triggerNotification("Table missing - item saved only for this session", 'error');
      const tempItem = { ...product, id: Math.random().toString(36).substr(2, 9), inStock: true };
      setItems(prev => [tempItem, ...prev]);
    }
  };

  const handleUpdateProduct = async (id: string, updates: Partial<FoodItem>) => {
    try {
      const { error } = await supabase.from('products').update(updates).eq('id', id);
      if (error) throw error;
      setItems(prev => prev.map(item => item.id === id ? { ...item, ...updates } : item));
      triggerNotification("Updated successfully", 'success');
    } catch (err) {
      triggerNotification("Update failed - local only", 'error');
      setItems(prev => prev.map(item => item.id === id ? { ...item, ...updates } : item));
    }
  };

  const handleDeleteProduct = async (id: string) => {
    try {
      const { error } = await supabase.from('products').delete().eq('id', id);
      if (error) throw error;
      setItems(prev => prev.filter(item => item.id !== id));
      triggerNotification("Item removed", 'success');
    } catch (err) {
      triggerNotification("Delete failed - local only", 'error');
      setItems(prev => prev.filter(item => item.id !== id));
    }
  };

  const handleToggleStock = async (id: string) => {
    const item = items.find(i => i.id === id);
    if (!item) return;
    const newStatus = !item.inStock;
    try {
      const { error } = await supabase.from('products').update({ inStock: newStatus }).eq('id', id);
      if (error) throw error;
      setItems(prev => prev.map(i => i.id === id ? { ...i, inStock: newStatus } : i));
      triggerNotification(`${item.name} is now ${newStatus ? 'In Stock' : 'Out of Stock'}`, 'info');
    } catch (err) {
      triggerNotification("Stock update failed - local only", 'error');
      setItems(prev => prev.map(i => i.id === id ? { ...i, inStock: newStatus } : i));
    }
  };

  const handleInstallClick = async () => {
    if (!installPrompt) return;
    installPrompt.prompt();
    await installPrompt.userChoice;
    setInstallPrompt(null);
  };

  const startListening = () => {
    if (isListening) return;

    // Support for standard API and WebKit prefix (iOS Safari)
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitRecognition;

    if (!SpeechRecognition) {
      triggerNotification("Voice search not supported on this browser", 'error');
      return;
    }

    try {
      const recognition = new SpeechRecognition();
      recognition.lang = 'en-US';
      recognition.interimResults = false;
      recognition.maxAlternatives = 1;

      recognition.onstart = () => {
        setIsListening(true);
      };

      recognition.onresult = (event: any) => {
        const transcript = event.results[0][0].transcript;
        setSearchQuery(transcript);
        // Optional: Auto-stop or just let it end naturally
      };

      recognition.onerror = (event: any) => {
        console.error('Speech recognition error', event.error);
        setIsListening(false);
        if (event.error === 'not-allowed') {
          triggerNotification("Mic access denied. Enable permissions in settings.", 'error');
        } else if (event.error === 'no-speech') {
          triggerNotification("No speech detected. Please try again.", 'info');
        } else {
          // Ignore minor errors or just log
          // triggerNotification("Voice search error", 'error');
        }
      };

      recognition.onend = () => {
        setIsListening(false);
      };

      recognition.start();
    } catch (err) {
      console.error(err);
      setIsListening(false);
      triggerNotification("Failed to start microphone", 'error');
    }
  };

  if (authLoading || menuLoading) {
    return <div className="h-screen flex items-center justify-center"><div className="w-10 h-10 border-4 border-orange-500 border-t-transparent rounded-full animate-spin"></div></div>;
  }

  if (!session) return <LandingPage />;

  return (
    <div className="flex flex-col h-screen w-full bg-white overflow-hidden relative font-sans">
      <header className="bg-orange-500 text-white shadow-md z-40 w-full shrink-0">
        <div className="max-w-7xl mx-auto px-4 py-3 flex items-center justify-between gap-3 sm:gap-6">
          <div className="flex items-center space-x-2 cursor-pointer shrink-0" onClick={() => setActiveTab('home')}>
             <div className="w-8 h-8 sm:w-10 sm:h-10 bg-white/20 backdrop-blur rounded-xl flex items-center justify-center border border-white/20">
               <i className="fas fa-utensils text-xs sm:text-base"></i>
             </div>
             <h1 className="text-lg sm:text-2xl font-black whitespace-nowrap tracking-tight">Hotel Anandam</h1>
          </div>
          <div className="flex-1 relative max-w-lg">
            <input 
              type="text" 
              placeholder="Find a dish..." 
              className="w-full pl-9 pr-9 py-2 sm:py-2.5 rounded-2xl bg-orange-400/30 text-white placeholder-orange-100 border-none focus:bg-white focus:text-gray-800 text-sm transition-all outline-none" 
              value={searchQuery} 
              onChange={(e) => setSearchQuery(e.target.value)} 
            />
            <i className="fas fa-search absolute left-3 top-1/2 -translate-y-1/2 text-orange-100 pointer-events-none"></i>
            <button 
              onClick={startListening} 
              className={`absolute right-2 top-1/2 -translate-y-1/2 w-7 h-7 flex items-center justify-center rounded-full transition-all ${
                isListening 
                  ? 'bg-red-500 text-white animate-pulse ring-2 ring-red-300' 
                  : 'text-orange-100 hover:text-white active:scale-95'
              }`}
              title="Voice Search"
            >
              <i className={`fas ${isListening ? 'fa-stop' : 'fa-microphone'}`}></i>
            </button>
          </div>
        </div>
      </header>
      <main className="flex-1 overflow-y-auto bg-gray-50 pb-24">
        {activeTab === 'home' && <HomeTab items={filteredItems} onAdd={addToCart} onInstall={handleInstallClick} showInstallButton={!!installPrompt} />}
        {activeTab === 'order' && <OrderTab cartItems={cart} onAdd={addToCart} onRemove={removeFromCart} onClear={clearCart} orderStatus={orderStatus} onPlaceOrder={handlePlaceOrder} onTrackOrder={() => setActiveTab('tracking')} />}
        {activeTab === 'tracking' && session?.user && <TrackingTab user={session.user} />}
        {activeTab === 'profile' && session?.user && <ProfileTab user={session.user} onOpenAdmin={() => setActiveTab('admin')} menuItems={items} onUpdateItem={handleUpdateProduct} onDeleteItem={handleDeleteProduct} onToggleStock={handleToggleStock} onAddItem={handleAddNewProduct} dbError={dbError} />}
        {activeTab === 'admin' && <AdminTab onClose={() => setActiveTab('profile')} />}
      </main>
      {showNotification && (
        <div className={`fixed bottom-24 left-1/2 -translate-x-1/2 px-6 py-3 rounded-2xl text-xs font-bold shadow-2xl z-50 flex items-center animate-in fade-in slide-in-from-bottom-4 ${showNotification.type === 'error' ? 'bg-red-600 text-white' : showNotification.type === 'success' ? 'bg-green-600 text-white' : 'bg-gray-900 text-white'}`}>
          <i className={`fas mr-2 ${showNotification.type === 'error' ? 'fa-circle-exclamation' : showNotification.type === 'success' ? 'fa-circle-check' : 'fa-info-circle text-orange-400'}`}></i>
          {showNotification.msg}
        </div>
      )}
      <div className="fixed bottom-0 left-0 right-0 bg-white border-t z-30">
        <BottomNav activeTab={activeTab === 'admin' ? 'profile' : activeTab} setActiveTab={setActiveTab} cartCount={cartTotalItems} />
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { supabase } from '../supabase';
import { Order, OrderStatus } from '../types';
import { jsPDF } from "jspdf";
import autoTable from "jspdf-autotable";

interface AdminTabProps {
  onClose?: () => void;
}

const AdminTab: React.FC<AdminTabProps> = ({ onClose }) => {
  const [orders, setOrders] = useState<Order[]>([]);
  const [loading, setLoading] = useState(true);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  useEffect(() => {
    // Initialize audio for new order notifications
    audioRef.current = new Audio('https://assets.mixkit.co/active_storage/sfx/2869/2869-preview.mp3');

    fetchOrders();

    // 1. Real-time Subscription
    const channel = supabase
      .channel('kitchen-dashboard')
      .on(
        'postgres_changes',
        { event: '*', schema: 'public', table: 'orders' },
        (payload) => {
          console.log('Change received!', payload);
          fetchOrders();

          // Play sound only on new orders
          if (payload.eventType === 'INSERT') {
            playNotificationSound();
          }
        }
      )
      .subscribe((status) => {
        if (status === 'SUBSCRIBED') {
          console.log('Kitchen Dashboard: Connected to real-time updates');
        }
      });

    // 2. Fallback Polling (Every 30 seconds)
    // Ensures data consistency even if the socket disconnects temporarily
    const intervalId = setInterval(() => {
      fetchOrders();
    }, 30000);

    return () => {
      supabase.removeChannel(channel);
      clearInterval(intervalId);
    };
  }, []);

  const playNotificationSound = () => {
    if (audioRef.current) {
      audioRef.current.play().catch(error => {
        console.warn("Audio play failed (user interaction might be needed first):", error);
      });
    }
  };

  const fetchOrders = async () => {
    try {
      const { data, error } = await supabase
        .from('orders')
        .select('*')
        .order('created_at', { ascending: false });
      if (error) throw error;
      setOrders(data || []);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const updateOrderStatus = async (orderId: string, newStatus: OrderStatus) => {
    try {
      const { error } = await supabase
        .from('orders')
        .update({ status: newStatus })
        .eq('id', orderId);
      if (error) throw error;
      // We don't strictly need to fetchOrders here because the subscription will catch the UPDATE event,
      // but calling it ensures instant UI feedback for the user who clicked.
      fetchOrders();
    } catch (err) {
      console.error('Status update failed:', err);
    }
  };

  const getDailyToken = (order: Order) => {
    const orderDate = new Date(order.created_at).toISOString().split('T')[0];
    const todayOrdersSorted = [...orders]
      .filter(o => o.created_at.startsWith(orderDate))
      .sort((a, b) => new Date(a.created_at).getTime() - new Date(b.created_at).getTime());

    const tokenIdx = todayOrdersSorted.findIndex(o => o.id === order.id);
    return tokenIdx !== -1 ? tokenIdx + 1 : 'N/A';
  };

  const calculateTodayRevenue = () => {
    const today = new Date().toISOString().split('T')[0];
    return orders
      .filter(o => o.created_at.startsWith(today) && o.status !== 'Cancelled')
      .reduce((sum, o) => sum + o.total_amount, 0);
  };

  const handleDownloadReport = () => {
    const todayStr = new Date().toISOString().split('T')[0];
    const todayOrders = orders
      .filter(o => o.created_at.startsWith(todayStr) && o.status !== 'Cancelled')
      .sort((a, b) => new Date(a.created_at).getTime() - new Date(b.created_at).getTime());

    if (todayOrders.length === 0) {
      alert("No sales data available for today yet.");
      return;
    }

    const doc = new jsPDF();
    const revenue = calculateTodayRevenue();

    doc.setFontSize(22);
    doc.setTextColor(249, 115, 22);
    doc.text("Hotel Anandam", 105, 20, { align: 'center' });

    doc.setFontSize(16);
    doc.setTextColor(31, 41, 55);
    doc.text("Daily Sales Report", 105, 30, { align: 'center' });

    doc.setFontSize(10);
    doc.setTextColor(107, 114, 128);
    doc.text(`Date: ${new Date().toLocaleDateString()}`, 105, 38, { align: 'center' });

    doc.setDrawColor(229, 231, 235);
    doc.setFillColor(249, 250, 251);
    doc.roundedRect(14, 45, 182, 20, 3, 3, 'FD');

    doc.setFontSize(11);
    doc.setTextColor(31, 41, 55);
    doc.text(`Total Orders: ${todayOrders.length}`, 20, 57);
    doc.text(`Total Revenue: Rs. ${revenue}`, 150, 57);

    const tableHeaders = [['Token', 'ID', 'Time', 'Customer Number', 'Items', 'Amount', 'Status']];
    const tableData = todayOrders.map((order, idx) => [
      idx + 1,
      order.id.slice(0, 6),
      new Date(order.created_at).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
      order.phone,
      order.items.map(i => `${i.quantity}x ${i.name}`).join(', '),
      `Rs. ${order.total_amount}`,
      order.status
    ]);

    autoTable(doc, {
      head: tableHeaders,
      body: tableData,
      startY: 75,
      styles: { fontSize: 8, cellPadding: 3 },
      headStyles: { fillColor: [249, 115, 22], textColor: 255 },
      alternateRowStyles: { fillColor: [255, 247, 237] },
    });

    const finalY = (doc as any).lastAutoTable.finalY || 75;
    doc.setFontSize(9);
    doc.setTextColor(156, 163, 175);
    doc.text(`Report generated at ${new Date().toLocaleTimeString()}`, 105, finalY + 20, { align: 'center' });

    doc.save(`HotelAnandam_Sales_${todayStr}.pdf`);
  };

  const handlePrintReceipt = (order: Order) => {
    const tokenNumber = getDailyToken(order);
    const printWindow = window.open('', '_blank', 'width=400,height=600');
    if (!printWindow) return;

    const itemsHtml = order.items.map(item => `
      <div style="display: flex; justify-content: space-between; margin-bottom: 5px; font-family: monospace;">
        <span>${item.quantity} x ${item.name}</span>
        <span>₹${item.price * item.quantity}</span>
      </div>
    `).join('');

    const htmlContent = `
      <html>
        <head>
          <title>Receipt - Hotel Anandam</title>
          <style>
            body { font-family: 'Courier New', Courier, monospace; padding: 20px; color: #000; }
            .header { text-align: center; border-bottom: 1px dashed #000; padding-bottom: 10px; margin-bottom: 15px; }
            .footer { border-top: 1px dashed #000; padding-top: 10px; margin-top: 15px; text-align: center; font-size: 12px; }
            .total { font-weight: bold; font-size: 18px; margin-top: 10px; display: flex; justify-content: space-between; }
            .info { font-size: 12px; margin-bottom: 15px; line-height: 1.6; }
            .bold-line { font-weight: 900; font-size: 14px; }
            .token-box { font-size: 32px; font-weight: 900; margin: 10px 0; border: 3px solid #000; display: inline-block; padding: 10px 25px; }
          </style>
        </head>
        <body onload="window.print(); window.close();">
          <div class="header">
            <h2 style="margin:0;">HOTEL ANANDAM</h2>
            <p style="margin:5px 0; font-size:12px;">Samayapuram, Madurai</p>
            <div class="token-box">TOKEN: ${tokenNumber}</div>
            <p style="margin:5px 0 0 0; font-size:11px; font-weight:bold;">TAX INVOICE</p>
          </div>
          <div class="info">
            <div>Order ID: #${order.id.slice(0, 8)}</div>
            <div>Date: ${new Date(order.created_at).toLocaleString()}</div>
            <div class="bold-line">Customer Number: ${order.phone}</div>
            <div class="bold-line">Location: ${order.location}</div>
          </div>
          <div style="border-bottom: 1px solid #000; margin-bottom: 10px;"></div>
          ${itemsHtml}
          <div style="display: flex; justify-content: space-between; font-size: 12px; margin-top: 10px;">
            <span>Delivery Fee</span>
            <span>₹30</span>
          </div>
          <div class="total">
            <span>TOTAL</span>
            <span>₹${order.total_amount}</span>
          </div>
          <div class="footer">
            <p>Thank you for choosing Hotel Anandam!</p>
            <p>Payment Mode: ${order.payment_method}</p>
          </div>
        </body>
      </html>
    `;

    printWindow.document.write(htmlContent);
    printWindow.document.close();
  };

  const revenue = calculateTodayRevenue();
  const pendingCount = orders.filter(o => o.status === 'Pending Acceptance').length;
  const completedCount = orders.filter(o => o.status === 'Delivered').length;

  return (
    <div className="p-4 sm:p-8 lg:p-12 max-w-7xl mx-auto space-y-8 pb-32">
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
        <div className="flex items-center space-x-4">
          {onClose && (
            <button 
              onClick={onClose} 
              className="w-12 h-12 rounded-full bg-white border border-gray-100 flex items-center justify-center text-gray-400 hover:text-orange-500 hover:border-orange-100 transition-all shadow-sm active:scale-95"
              title="Exit Kitchen Dashboard"
            >
              <i className="fas fa-arrow-left"></i>
            </button>
          )}
          <div>
            <h2 className="text-3xl font-black text-gray-900 tracking-tight flex items-center">
              Kitchen Dashboard
              <span className="ml-3 flex h-3 w-3">
                <span className="animate-ping absolute inline-flex h-3 w-3 rounded-full bg-green-400 opacity-75"></span>
                <span className="relative inline-flex rounded-full h-3 w-3 bg-green-500"></span>
              </span>
            </h2>
            <p className="text-gray-500 font-medium italic">Operations Control Center</p>
          </div>
        </div>

        <div className="grid grid-cols-3 gap-3">
          <div className="bg-white p-3 sm:p-4 rounded-2xl border border-gray-100 shadow-sm text-center">
            <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">Today Sales</p>
            <p className="text-lg font-black text-orange-600">₹{revenue}</p>
          </div>
          <div className="bg-white p-3 sm:p-4 rounded-2xl border border-gray-100 shadow-sm text-center">
            <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">New Orders</p>
