  const [items, setItems] = useState<FoodItem[]>([]);
  const [menuLoading, setMenuLoading] = useState(true);
  const [orderStatus, setOrderStatus] = useState<'idle' | 'processing' | 'success'>('idle');
  const [installPrompt, setInstallPrompt] = useState<any>(null);
  const [dbError, setDbError] = useState<string | null>(null);

  const [searchQuery, setSearchQuery] = useState('');
  const [isListening, setIsListening] = useState(false);

  // Filter items based on the search query
  const filteredItems = items.filter(item => 
    item.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
    item.category.toLowerCase().includes(searchQuery.toLowerCase()) ||
    (item.description && item.description.toLowerCase().includes(searchQuery.toLowerCase()))
  );

  const cartTotalItems = cart.reduce((acc, curr) => acc + curr.quantity, 0);

  useEffect(() => {
    const initAuth = async () => {
      try {
        const { data: { session } } = await supabase.auth.getSession();
        setSession(session);
      } catch (e) {
        console.error('Initial session fetch failed', e);
      } finally {
        setAuthLoading(false);
      }
    };

    initAuth();
    fetchMenuItems();

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
    });

    const menuSubscription = supabase
      .channel('menu-changes')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'products' }, fetchMenuItems)
      .subscribe();

    const handleBeforeInstallPrompt = (e: Event) => {
      e.preventDefault();
      setInstallPrompt(e);
    };

    window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt);

    return () => {
      subscription.unsubscribe();
      menuSubscription.unsubscribe();
      window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
    };
  }, []);

  const fetchMenuItems = async () => {
    try {
      const { data, error } = await supabase
        .from('products')
        .select('*')
        .order('created_at', { ascending: false });

      if (error) {
        if (error.code === 'PGRST205' || error.message.includes('relation "products" does not exist')) {
          setDbError("Database table 'products' missing.");
        }
        throw error;
      }

      setDbError(null);
      if (data && data.length > 0) {
        setItems(data);
      } else {
        setItems(FOOD_ITEMS);
      }
    } catch (err) {
      console.warn('DB Fetch failed, using fallback items');
      if (items.length === 0) setItems(FOOD_ITEMS);
    } finally {
      setMenuLoading(false);
    }
  };

  const triggerNotification = (msg: string, type: 'info' | 'error' | 'success' = 'info') => {
    setShowNotification({ msg, type });
    setTimeout(() => setShowNotification(null), 3000);
  };

  const addToCart = (item: FoodItem) => {
    if (!item.inStock) {
      triggerNotification(`${item.name} is out of stock!`, 'error');
      return;
    }
    if (orderStatus === 'success') setOrderStatus('idle');
    setCart(prev => {
      const existing = prev.find(i => i.id === item.id);
      if (existing) {
        return prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i);
      }
      return [...prev, { ...item, quantity: 1 }];
    });
    triggerNotification(`${item.name} added!`, 'success');
  };

  const removeFromCart = (itemId: string) => {
    setCart(prev => {
      const existing = prev.find(i => i.id === itemId);
      if (existing && existing.quantity > 1) {
        return prev.map(i => i.id === itemId ? { ...i, quantity: i.quantity - 1 } : i);
      }
      return prev.filter(i => i.id !== itemId);
    });
  };

  const clearCart = () => setCart([]);

  const handlePlaceOrder = async (phone: string, location: string, paymentMethod: 'COD' | 'GPay') => {
    if (cart.length === 0 || !session?.user) return;
    setOrderStatus('processing');
    const total = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0) + 30;

    try {
      const { error } = await supabase.from('orders').insert([{
        user_id: session.user.id,
        user_email: session.user.email,
        phone, 
        location, 
        items: cart, 
        total_amount: total,
        status: 'Pending Acceptance', 
        payment_method: paymentMethod
      }]);

      if (error) throw error;

      setTimeout(() => { 
        setOrderStatus('success'); 
        setCart([]); 
      }, 1500);
    } catch (err: any) {
      console.error('Order placement error:', err);
      triggerNotification(`Order failed: ${err.message || 'Database error'}`, 'error');
      setOrderStatus('idle');
    }
  };

  const handleAddNewProduct = async (product: Omit<FoodItem, 'id'>) => {
    try {
      const { data, error } = await supabase.from('products').insert([{ ...product, inStock: true }]).select();
      if (error) throw error;
      if (data) {
        setItems(prev => [data[0], ...prev]);
        triggerNotification(`${product.name} saved!`, 'success');
      }
    } catch (err: any) {
      triggerNotification("Table missing - item saved locally", 'info');
      const tempItem = { ...product, id: Math.random().toString(36).substr(2, 9), inStock: true };
      setItems(prev => [tempItem, ...prev]);
    }
  };

  const handleUpdateProduct = async (id: string, updates: Partial<FoodItem>) => {
    try {
      const { error } = await supabase.from('products').update(updates).eq('id', id);
      if (error) throw error;
      setItems(prev => prev.map(item => item.id === id ? { ...item, ...updates } : item));
      triggerNotification("Updated successfully", 'success');
    } catch (err) {
      triggerNotification("Update failed - local only", 'info');
      setItems(prev => prev.map(item => item.id === id ? { ...item, ...updates } : item));
    }
  };

  const handleDeleteProduct = async (id: string) => {
    try {
      const { error } = await supabase.from('products').delete().eq('id', id);
      if (error) throw error;
      setItems(prev => prev.filter(item => item.id !== id));
      triggerNotification("Item removed", 'success');
    } catch (err) {
      triggerNotification("Delete failed - local only", 'info');
      setItems(prev => prev.filter(item => item.id !== id));
    }
  };

  const handleToggleStock = async (id: string) => {
    const item = items.find(i => i.id === id);
    if (!item) return;
    const newStatus = !item.inStock;
    try {
      const { error } = await supabase.from('products').update({ inStock: newStatus }).eq('id', id);
      if (error) throw error;
      setItems(prev => prev.map(i => i.id === id ? { ...i, inStock: newStatus } : i));
      triggerNotification(`${item.name} is now ${newStatus ? 'In Stock' : 'Out of Stock'}`, 'info');
    } catch (err) {
      triggerNotification("Stock update failed - local only", 'info');
      setItems(prev => prev.map(i => i.id === id ? { ...i, inStock: newStatus } : i));
    }
  };

  const handleInstallClick = async () => {
    if (!installPrompt) return;
    installPrompt.prompt();
    await installPrompt.userChoice;
    setInstallPrompt(null);
  };

  const startListening = () => {
    if (isListening) return;

    // Support for standard API and WebKit prefix (iOS Safari)
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitRecognition;

    if (!SpeechRecognition) {
      triggerNotification("Voice search not supported on this browser", 'error');
      return;
    }

    try {
      const recognition = new SpeechRecognition();
      recognition.lang = 'en-US';
      recognition.interimResults = false;
      recognition.maxAlternatives = 1;

      recognition.onstart = () => {
        setIsListening(true);
      };

      recognition.onresult = (event: any) => {
        const transcript = event.results[0][0].transcript;
        setSearchQuery(transcript);
        // Optional: Auto-stop or just let it end naturally
      };

      recognition.onerror = (event: any) => {
        console.error('Speech recognition error', event.error);
        setIsListening(false);
        if (event.error === 'not-allowed') {
          triggerNotification("Mic access denied. Enable permissions in settings.", 'error');
        } else if (event.error === 'no-speech') {
          triggerNotification("No speech detected. Please try again.", 'info');
        } else {
          // Ignore minor errors or just log
          // triggerNotification("Voice search error", 'error');
        }
      };

      recognition.onend = () => {
        setIsListening(false);
      };

      recognition.start();
    } catch (err) {
      console.error(err);
      setIsListening(false);
      triggerNotification("Failed to start microphone", 'error');
    }
  };

  if (authLoading || menuLoading) {
    return <div className="h-screen flex items-center justify-center"><div className="w-10 h-10 border-4 border-orange-500 border-t-transparent rounded-full animate-spin"></div></div>;
  }

  if (!session) return <LandingPage />;

  return (
    <div className="flex flex-col h-screen w-full bg-white overflow-hidden relative font-sans">
      <header className="bg-orange-500 text-white shadow-md z-40 w-full shrink-0">
        <div className="max-w-7xl mx-auto px-4 py-3 flex items-center justify-between gap-3 sm:gap-6">
          <div className="flex items-center space-x-2 cursor-pointer shrink-0" onClick={() => setActiveTab('home')}>
             <div className="w-8 h-8 sm:w-10 sm:h-10 bg-white/20 backdrop-blur rounded-xl flex items-center justify-center border border-white/20">
               <i className="fas fa-utensils text-xs sm:text-base"></i>
             </div>
             <h1 className="text-lg sm:text-2xl font-black whitespace-nowrap tracking-tight">Hotel Anandam</h1>
          </div>
          <div className="flex-1 relative max-w-lg">
            <input 
              type="text" 
              placeholder="Find a dish..." 
              className="w-full pl-9 pr-9 py-2 sm:py-2.5 rounded-2xl bg-orange-400/30 text-white placeholder-orange-100 border-none focus:bg-white focus:text-gray-800 text-sm transition-all outline-none" 
              value={searchQuery} 
              onChange={(e) => setSearchQuery(e.target.value)} 
            />
            <i className="fas fa-search absolute left-3 top-1/2 -translate-y-1/2 text-orange-100 pointer-events-none"></i>
            <button 
              onClick={startListening} 
              className={`absolute right-2 top-1/2 -translate-y-1/2 w-7 h-7 flex items-center justify-center rounded-full transition-all ${
                isListening 
                  ? 'bg-red-500 text-white animate-pulse ring-2 ring-red-300' 
                  : 'text-orange-100 hover:text-white active:scale-95'
              }`}
              title="Voice Search"
            >
              <i className={`fas ${isListening ? 'fa-stop' : 'fa-microphone'}`}></i>
            </button>
          </div>
        </div>
      </header>
      <main className="flex-1 overflow-y-auto bg-gray-50 pb-24">
        {activeTab === 'home' && <HomeTab items={filteredItems} onAdd={addToCart} onInstall={handleInstallClick} showInstallButton={!!installPrompt} />}
        {activeTab === 'order' && <OrderTab cartItems={cart} onAdd={addToCart} onRemove={removeFromCart} onClear={clearCart} orderStatus={orderStatus} onPlaceOrder={handlePlaceOrder} onTrackOrder={() => setActiveTab('tracking')} />}
        {activeTab === 'tracking' && session?.user && <TrackingTab user={session.user} />}
        {activeTab === 'profile' && session?.user && <ProfileTab user={session.user} onOpenAdmin={() => setActiveTab('admin')} menuItems={items} onUpdateItem={handleUpdateProduct} onDeleteItem={handleDeleteProduct} onToggleStock={handleToggleStock} onAddItem={handleAddNewProduct} dbError={dbError} />}
        {activeTab === 'admin' && <AdminTab onClose={() => setActiveTab('profile')} />}
      </main>
      {showNotification && (
        <div className={`fixed bottom-24 left-1/2 -translate-x-1/2 px-6 py-3 rounded-2xl text-xs font-bold shadow-2xl z-50 flex items-center animate-in fade-in slide-in-from-bottom-4 ${showNotification.type === 'error' ? 'bg-red-600 text-white' : showNotification.type === 'success' ? 'bg-green-600 text-white' : 'bg-gray-900 text-white'}`}>
          <i className={`fas mr-2 ${showNotification.type === 'error' ? 'fa-circle-exclamation' : showNotification.type === 'success' ? 'fa-circle-check' : 'fa-info-circle text-orange-400'}`}></i>
          {showNotification.msg}
        </div>
      )}
      <div className="fixed bottom-0 left-0 right-0 bg-white border-t z-30">
        <BottomNav activeTab={activeTab === 'admin' ? 'profile' : activeTab} setActiveTab={setActiveTab} cartCount={cartTotalItems} />
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Order } from '../types';
import { supabase } from '../supabase';
import { User } from '@supabase/supabase-js';

interface TrackingTabProps {
  user: User;
}

const TrackingTab: React.FC<TrackingTabProps> = ({ user }) => {
  const [orders, setOrders] = useState<Order[]>([]);
  const [loading, setLoading] = useState(true);
  const [tokens, setTokens] = useState<Record<string, number>>({});

  useEffect(() => {
    if (user?.email) {
      fetchOrderHistory();
      const subscription = supabase
        .channel('user-tracking-channel')
        .on('postgres_changes', { 
          event: 'UPDATE', 
          schema: 'public', 
          table: 'orders', 
          filter: `user_email=eq.${user.email}` 
        }, fetchOrderHistory)
        .subscribe();

      return () => {
        subscription.unsubscribe();
      };
    }
  }, [user]);

  const fetchOrderHistory = async () => {
    if (!user?.email) return;
    setLoading(true);

    try {
      const { data, error } = await supabase
        .from('orders')
        .select('*')
        .eq('user_email', user.email)
        .order('created_at', { ascending: false });

      if (!error && data) {
        setOrders(data);
        fetchTokens(data);
      }
    } catch (err) {
      console.warn('Error fetching tracking history from DB:', err);
    } finally {
      setLoading(false);
    }
  };

  const fetchTokens = async (ordersList: Order[]) => {
    const tokenMap: Record<string, number> = {};

    await Promise.all(ordersList.map(async (order) => {
      try {
        const datePart = order.created_at.split('T')[0]; 
        const startOfDay = `${datePart}T00:00:00.000Z`;

        const { count } = await supabase
          .from('orders')
          .select('*', { count: 'exact', head: true })
          .gte('created_at', startOfDay)
          .lte('created_at', order.created_at);

        if (count !== null) tokenMap[order.id] = count;
      } catch (e) {
        console.error("Failed to fetch token for order", order.id);
      }
    }));

    setTokens(prev => ({...prev, ...tokenMap}));
  };

  return (
    <div className="p-4 sm:p-8 lg:p-12 max-w-4xl mx-auto animate-in fade-in slide-in-from-bottom-4 duration-500">
      <h3 className="text-2xl sm:text-3xl font-black text-gray-900 mb-8 px-1">Track Orders</h3>

      {loading && orders.length === 0 ? (
        <div className="flex flex-col items-center justify-center py-20">
          <div className="w-10 h-10 border-4 border-orange-500 border-t-transparent rounded-full animate-spin"></div>
          <p className="text-gray-400 mt-4 font-medium italic text-sm">Locating your orders...</p>
        </div>
      ) : orders.length === 0 ? (
        <div className="flex flex-col items-center justify-center py-20 bg-white rounded-[2.5rem] border border-dashed border-gray-200 shadow-sm">
          <div className="w-20 h-20 bg-gray-50 rounded-full flex items-center justify-center mb-6">
            <i className="fas fa-box-open text-3xl opacity-20"></i>
          </div>
          <p className="font-bold text-lg text-gray-600">No active orders</p>
          <p className="text-sm mt-1">Order something famous to see it here!</p>
        </div>
      ) : (
        <div className="space-y-6">
          {orders.map((order) => (
            <div key={order.id} className="bg-white rounded-[2rem] p-6 border border-gray-50 shadow-sm relative overflow-hidden group hover:shadow-md transition-shadow">

              {/* Token Badge */}
              {tokens[order.id] && (
                <div className="absolute top-0 right-0 bg-gray-900 text-white px-4 py-2 rounded-bl-2xl shadow-sm z-10 border-b border-l border-white/10">
                   <p className="text-[8px] uppercase tracking-widest opacity-70 font-bold mb-0.5">Token</p>
                   <p className="text-xl font-black leading-none text-center">#{tokens[order.id]}</p>
                </div>
              )}

              <div className="flex justify-between items-start mb-6 pr-16">
                <div>
                  <div className="flex items-center space-x-2">
                    <span className={`text-[10px] font-black px-3 py-1 rounded-full uppercase tracking-widest ${
                      order.status === 'Pending Acceptance' ? 'bg-amber-100 text-amber-600' :
                      order.status === 'Preparing' ? 'bg-blue-100 text-blue-600' :
                      order.status === 'Ready' ? 'bg-green-100 text-green-600' :
                      order.status === 'Delivered' ? 'bg-gray-100 text-gray-500' : 'bg-red-100 text-red-600'
                    }`}>
                      {order.status}
                    </span>
                    {order.status !== 'Delivered' && (
                       <span className="flex h-2 w-2 rounded-full bg-orange-500 animate-ping"></span>
                    )}
                  </div>
                  <p className="text-[10px] text-gray-400 font-bold uppercase mt-2 tracking-tighter">
                    ID: {order.id.slice(0, 8)} • {new Date(order.created_at).toLocaleDateString()} at {new Date(order.created_at).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                  </p>
                </div>
              </div>

              <div className="bg-gray-50 rounded-2xl p-4 space-y-3">
                {order.items.map((item, idx) => (
                  <div key={idx} className="flex justify-between items-center text-xs">
                    <div className="flex items-center space-x-2">
                      <span className="w-5 h-5 bg-white rounded-md flex items-center justify-center font-black text-orange-500 border border-gray-100">{item.quantity}</span>
                      <span className="text-gray-700 font-bold">{item.name}</span>
                    </div>
                    <span className="text-gray-400 font-medium">₹{item.price * item.quantity}</span>
                  </div>
                ))}

                <div className="pt-3 border-t border-gray-200 mt-2 flex justify-between items-center">
                   <div className="flex items-center text-[10px] font-black text-gray-400 uppercase tracking-widest">
                     <i className="fas fa-location-dot mr-1.5 text-orange-400"></i>
                     {order.location}
                   </div>
                   <div className="text-right">
                    <p className="text-lg font-black text-orange-600">₹{order.total_amount}</p>
                  </div>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default TrackingTab;

import React, { useState, useEffect, useRef } from 'react';
import { supabase } from '../supabase';
import { Order, OrderStatus } from '../types';
import { jsPDF } from "jspdf";
import autoTable from "jspdf-autotable";

interface AdminTabProps {
  onClose?: () => void;
}

const AdminTab: React.FC<AdminTabProps> = ({ onClose }) => {
  const [orders, setOrders] = useState<Order[]>([]);
  const [loading, setLoading] = useState(true);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  useEffect(() => {
    audioRef.current = new Audio('https://assets.mixkit.co/active_storage/sfx/2869/2869-preview.mp3');

    fetchOrders();

    const channel = supabase
      .channel('kitchen-dashboard')
      .on(
        'postgres_changes',
        { event: '*', schema: 'public', table: 'orders' },
        (payload) => {
          fetchOrders();
          if (payload.eventType === 'INSERT') {
            playNotificationSound();
          }
        }
      )
      .subscribe();

    const intervalId = setInterval(() => {
      fetchOrders();
    }, 30000); 

    return () => {
      supabase.removeChannel(channel);
      clearInterval(intervalId);
    };
  }, []);

  const playNotificationSound = () => {
    if (audioRef.current) {
      audioRef.current.play().catch(error => {
        console.warn("Audio play failed:", error);
      });
    }
  };

  const fetchOrders = async () => {
    try {
      const { data, error } = await supabase
        .from('orders')
        .select('*')
        .order('created_at', { ascending: false });

      if (!error && data) {
        setOrders(data);
      }
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const updateOrderStatus = async (orderId: string, newStatus: OrderStatus) => {
    try {
      const { error } = await supabase
        .from('orders')
        .update({ status: newStatus })
        .eq('id', orderId);
      if (error) throw error;
      fetchOrders();
    } catch (err) {
      console.error('Status update failed:', err);
    }
  };

  const getDailyToken = (order: Order) => {
    const orderDate = new Date(order.created_at).toISOString().split('T')[0];
    const todayOrdersSorted = [...orders]
      .filter(o => o.created_at.startsWith(orderDate))
      .sort((a, b) => new Date(a.created_at).getTime() - new Date(b.created_at).getTime());

    const tokenIdx = todayOrdersSorted.findIndex(o => o.id === order.id);
    return tokenIdx !== -1 ? tokenIdx + 1 : 'N/A';
  };

  const calculateTodayRevenue = () => {
    const today = new Date().toISOString().split('T')[0];
    return orders
      .filter(o => o.created_at.startsWith(today) && o.status !== 'Cancelled')
      .reduce((sum, o) => sum + o.total_amount, 0);
  };

  const handleDownloadReport = () => {
    const todayStr = new Date().toISOString().split('T')[0];
    const todayOrders = orders
      .filter(o => o.created_at.startsWith(todayStr) && o.status !== 'Cancelled')
      .sort((a, b) => new Date(a.created_at).getTime() - new Date(b.created_at).getTime());

    if (todayOrders.length === 0) {
      alert("No sales data available for today yet.");
      return;
    }

    const doc = new jsPDF();
    const revenue = calculateTodayRevenue();

    doc.setFontSize(22);
    doc.setTextColor(249, 115, 22);
    doc.text("Hotel Anandam", 105, 20, { align: 'center' });
    doc.setFontSize(16);
    doc.setTextColor(31, 41, 55);
    doc.text("Daily Sales Report", 105, 30, { align: 'center' });

    const tableHeaders = [['Token', 'ID', 'Time', 'Customer Number', 'Amount', 'Status']];
    const tableData = todayOrders.map((order) => [
      getDailyToken(order),
      order.id.slice(0, 6),
      new Date(order.created_at).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
      order.phone,
      `Rs. ${order.total_amount}`,
      order.status
    ]);

    autoTable(doc, {
      head: tableHeaders,
      body: tableData,
      startY: 50,
    });

    doc.save(`HotelAnandam_Sales_${todayStr}.pdf`);
  };

  const handlePrintReceipt = (order: Order) => {
    const tokenNumber = getDailyToken(order);
    const printWindow = window.open('', '_blank', 'width=400,height=600');
    if (!printWindow) return;

    const itemsHtml = order.items.map(item => `
      <div style="display: flex; justify-content: space-between; margin-bottom: 5px; font-family: monospace;">
        <span>${item.quantity} x ${item.name}</span>
        <span>₹${item.price * item.quantity}</span>
      </div>
    `).join('');

    const htmlContent = `
      <html>
        <head>
          <title>Receipt - Hotel Anandam</title>
          <style>
            body { font-family: 'Courier New', Courier, monospace; padding: 20px; color: #000; }
            .header { text-align: center; border-bottom: 1px dashed #000; padding-bottom: 10px; margin-bottom: 15px; }
            .token-box { font-size: 32px; font-weight: 900; margin: 10px 0; border: 3px solid #000; display: inline-block; padding: 10px 25px; }
            .total { font-weight: bold; font-size: 18px; margin-top: 10px; display: flex; justify-content: space-between; }
          </style>
        </head>
        <body onload="window.print(); window.close();">
          <div class="header">
            <h2 style="margin:0;">HOTEL ANANDAM</h2>
            <div class="token-box">TOKEN: ${tokenNumber}</div>
            <p style="margin:5px 0 0 0; font-size:11px; font-weight:bold;">TAX INVOICE</p>
          </div>
          <div>
            Order ID: #${order.id.slice(0, 8)}<br/>
            Date: ${new Date(order.created_at).toLocaleString()}<br/>
            Phone: ${order.phone}<br/>
            Loc: ${order.location}
          </div>
          <div style="border-bottom: 1px solid #000; margin: 10px 0;"></div>
          ${itemsHtml}
          <div class="total">
            <span>TOTAL</span>
            <span>₹${order.total_amount}</span>
          </div>
        </body>
      </html>
    `;
    printWindow.document.write(htmlContent);
    printWindow.document.close();
  };

  const revenue = calculateTodayRevenue();
  const pendingCount = orders.filter(o => o.status === 'Pending Acceptance').length;
  const completedCount = orders.filter(o => o.status === 'Delivered').length;

  return (
    <div className="p-4 sm:p-8 lg:p-12 max-w-7xl mx-auto space-y-8 pb-32">
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
        <div className="flex items-center space-x-4">
          {onClose && (
            <button onClick={onClose} className="w-12 h-12 rounded-full bg-white border border-gray-100 flex items-center justify-center text-gray-400 hover:text-orange-500 transition-all shadow-sm">
              <i className="fas fa-arrow-left"></i>
            </button>
          )}
          <div>
            <h2 className="text-3xl font-black text-gray-900 tracking-tight flex items-center">
              Kitchen Dashboard
              <span className="ml-3 flex h-3 w-3 relative">
                <span className="animate-ping absolute inline-flex h-3 w-3 rounded-full bg-green-400 opacity-75"></span>
                <span className="relative inline-flex rounded-full h-3 w-3 bg-green-500"></span>
              </span>
            </h2>
          </div>
        </div>
        <div className="grid grid-cols-3 gap-3">
          <div className="bg-white p-3 sm:p-4 rounded-2xl border border-gray-100 shadow-sm text-center">
            <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">Sales</p>
            <p className="text-lg font-black text-orange-600">₹{revenue}</p>
          </div>
          <div className="bg-white p-3 sm:p-4 rounded-2xl border border-gray-100 shadow-sm text-center">
            <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">New</p>
            <p className="text-lg font-black text-amber-500">{pendingCount}</p>
          </div>
          <div className="bg-white p-3 sm:p-4 rounded-2xl border border-gray-100 shadow-sm text-center">
            <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">Done</p>
            <p className="text-lg font-black text-green-500">{completedCount}</p>
          </div>
        </div>
      </div>

      <div className="space-y-6">
        <div className="flex items-center justify-between px-1">
          <h3 className="text-xl font-bold text-gray-800">Live Order Queue</h3>
          <div className="flex gap-2">
            <button onClick={handleDownloadReport} className="px-3 py-2 bg-gray-900 text-white rounded-xl text-[10px] font-black uppercase"><i className="fas fa-file-pdf mr-2"></i> Report</button>
            <button onClick={fetchOrders} className="px-3 py-2 bg-blue-50 text-blue-600 rounded-xl text-[10px] font-black uppercase"><i className="fas fa-sync-alt mr-2"></i> Sync</button>
          </div>
        </div>

        {loading ? (
          <div className="py-20 flex justify-center"><div className="w-10 h-10 border-4 border-orange-500 border-t-transparent rounded-full animate-spin"></div></div>
        ) : orders.length === 0 ? (
          <div className="bg-white p-20 rounded-[2.5rem] border border-dashed border-gray-200 text-center shadow-sm">
            <div className="w-20 h-20 bg-gray-50 rounded-full flex items-center justify-center mx-auto mb-6"><i className="fas fa-utensils text-3xl text-gray-200"></i></div>
            <p className="text-gray-400 font-bold">No orders yet...</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {orders.map((order) => {
              const token = getDailyToken(order);
              return (
                <div key={order.id} className="bg-white p-6 rounded-[2.5rem] border border-gray-50 shadow-sm hover:shadow-lg transition-all relative overflow-hidden flex flex-col group">
                  <div className="absolute -top-1 -right-1 w-12 h-12 bg-gray-900 text-white flex items-center justify-center font-black rounded-bl-3xl shadow-lg z-10">
                    {token}
                  </div>

                  {order.status !== 'Pending Acceptance' && order.status !== 'Cancelled' && (
                    <button onClick={() => handlePrintReceipt(order)} className="absolute top-16 right-6 w-10 h-10 bg-orange-50 text-orange-600 rounded-full flex items-center justify-center hover:bg-orange-500 hover:text-white transition-all shadow-sm z-10"><i className="fas fa-print"></i></button>
                  )}

                  <div className="flex justify-between items-start mb-6">
                    <div className="space-y-1">
                      <span className={`text-[10px] font-black px-3 py-1 rounded-full uppercase tracking-widest ${
                        order.status === 'Pending Acceptance' ? 'bg-amber-100 text-amber-600 animate-pulse' :
                        order.status === 'Preparing' ? 'bg-blue-100 text-blue-600' :
                        order.status === 'Ready' ? 'bg-green-100 text-green-600' : 'bg-gray-100 text-gray-600'
                      }`}>{order.status}</span>
                      <p className="text-[10px] text-gray-400 font-bold mt-1 uppercase tracking-tighter">#{order.id.slice(0, 8)}</p>
                    </div>
                    <div className={`text-right ${order.status === 'Pending Acceptance' ? 'pr-2' : 'pr-12'}`}>
                       <p className="text-lg font-black text-gray-900">₹{order.total_amount}</p>
                    </div>
                  </div>

                  <div className="space-y-4 mb-6">
                    <div className="flex items-center space-x-3">
                      <div className="w-10 h-10 bg-gray-50 rounded-xl flex items-center justify-center text-orange-400"><i className="fas fa-location-dot"></i></div>
                      <div><p className="text-xs font-black text-gray-800 uppercase tracking-tight">{order.location}</p><p className="text-[10px] text-gray-500 font-bold">{order.phone}</p></div>
                    </div>
                  </div>

                  <div className="bg-gray-50 rounded-2xl p-4 space-y-2 flex-1">
                    <p className="text-[9px] font-black text-gray-400 uppercase tracking-widest mb-2 flex justify-between">Items <span>{new Date(order.created_at).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span></p>
                    {order.items.map((item, idx) => (
                      <div key={idx} className="flex justify-between items-center text-xs">
                        <span className="text-gray-700 font-bold"><span className="text-orange-500 font-black mr-1">{item.quantity}x</span>{item.name}</span>
                      </div>
                    ))}
                  </div>

                  <div className="mt-6 space-y-2">
                    {order.status === 'Pending Acceptance' && (
                      <button onClick={() => updateOrderStatus(order.id, 'Preparing')} className="w-full bg-orange-600 text-white py-4 rounded-2xl font-black text-xs uppercase tracking-widest shadow-lg shadow-orange-100 active:scale-95 transition-all flex items-center justify-center group"><i className="fas fa-check-circle mr-2"></i>Accept Order</button>
                    )}
                    {order.status === 'Preparing' && (
                      <button onClick={() => updateOrderStatus(order.id, 'Ready')} className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black text-xs uppercase tracking-widest shadow-lg shadow-blue-100 active:scale-95 transition-all flex items-center justify-center"><i className="fas fa-utensils mr-2"></i>Mark Ready</button>
                    )}
                    {order.status === 'Ready' && (
                      <button onClick={() => updateOrderStatus(order.id, 'Delivered')} className="w-full bg-gray-900 text-white py-4 rounded-2xl font-black text-xs uppercase tracking-widest active:scale-95 transition-all flex items-center justify-center"><i className="fas fa-truck mr-2 text-orange-400"></i>Confirm Delivered</button>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
};

export default AdminTab;

import React, { useState, useEffect } from 'react';
import { Order } from '../types';
import { supabase } from '../supabase';
import { User } from '@supabase/supabase-js';

interface TrackingTabProps {
  user: User;
}

const TrackingTab: React.FC<TrackingTabProps> = ({ user }) => {
  const [orders, setOrders] = useState<Order[]>([]);
  const [loading, setLoading] = useState(true);
  const [tokens, setTokens] = useState<Record<string, number>>({});

  useEffect(() => {
    if (user?.id) {
      fetchOrderHistory();

      // Subscribe to changes for this specific user ID
      const subscription = supabase
        .channel('user-tracking-channel')
        .on('postgres_changes', { 
          event: 'UPDATE', 
          schema: 'public', 
          table: 'orders', 
          filter: `user_id=eq.${user.id}` 
        }, fetchOrderHistory)
        .subscribe();

      return () => {
        subscription.unsubscribe();
      };
    }
  }, [user]);

  const fetchOrderHistory = async () => {
    if (!user?.id) return;
    setLoading(true);

    try {
      const { data, error } = await supabase
        .from('orders')
        .select('*')
        .eq('user_id', user.id) // Filter by ID now that the column exists
        .order('created_at', { ascending: false });

      if (!error && data) {
        setOrders(data);
        fetchTokens(data);
      }
    } catch (err) {
      console.warn('Error fetching tracking history from DB:', err);
    } finally {
      setLoading(false);
    }
  };

  const fetchTokens = async (ordersList: Order[]) => {
    const tokenMap: Record<string, number> = {};

    await Promise.all(ordersList.map(async (order) => {
      try {
        const datePart = order.created_at.split('T')[0]; 
        const startOfDay = `${datePart}T00:00:00.000Z`;

        const { count } = await supabase
          .from('orders')
          .select('*', { count: 'exact', head: true })
          .gte('created_at', startOfDay)
          .lte('created_at', order.created_at);

        if (count !== null) tokenMap[order.id] = count;
      } catch (e) {
        console.error("Failed to fetch token for order", order.id);
      }
    }));

    setTokens(prev => ({...prev, ...tokenMap}));
  };

  return (
    <div className="p-4 sm:p-8 lg:p-12 max-w-4xl mx-auto animate-in fade-in slide-in-from-bottom-4 duration-500">
      <h3 className="text-2xl sm:text-3xl font-black text-gray-900 mb-8 px-1">Track Orders</h3>

      {loading && orders.length === 0 ? (
        <div className="flex flex-col items-center justify-center py-20">
          <div className="w-10 h-10 border-4 border-orange-500 border-t-transparent rounded-full animate-spin"></div>
          <p className="text-gray-400 mt-4 font-medium italic text-sm">Locating your orders...</p>
        </div>
      ) : orders.length === 0 ? (
        <div className="flex flex-col items-center justify-center py-20 bg-white rounded-[2.5rem] border border-dashed border-gray-200 shadow-sm">
          <div className="w-20 h-20 bg-gray-50 rounded-full flex items-center justify-center mb-6">
            <i className="fas fa-box-open text-3xl opacity-20"></i>
          </div>
          <p className="font-bold text-lg text-gray-600">No active orders</p>
          <p className="text-sm mt-1">Order something famous to see it here!</p>
        </div>
      ) : (
        <div className="space-y-6">
          {orders.map((order) => (
            <div key={order.id} className="bg-white rounded-[2rem] p-6 border border-gray-50 shadow-sm relative overflow-hidden group hover:shadow-md transition-shadow">

              {/* Token Badge */}
              {tokens[order.id] && (
                <div className="absolute top-0 right-0 bg-gray-900 text-white px-4 py-2 rounded-bl-2xl shadow-sm z-10 border-b border-l border-white/10">
                   <p className="text-[8px] uppercase tracking-widest opacity-70 font-bold mb-0.5">Token</p>
                   <p className="text-xl font-black leading-none text-center">#{tokens[order.id]}</p>
                </div>
              )}

              <div className="flex justify-between items-start mb-6 pr-16">
                <div>
                  <div className="flex items-center space-x-2">
                    <span className={`text-[10px] font-black px-3 py-1 rounded-full uppercase tracking-widest ${
                      order.status === 'Pending Acceptance' ? 'bg-amber-100 text-amber-600' :
                      order.status === 'Preparing' ? 'bg-blue-100 text-blue-600' :
                      order.status === 'Ready' ? 'bg-green-100 text-green-600' :
                      order.status === 'Delivered' ? 'bg-gray-100 text-gray-500' : 'bg-red-100 text-red-600'
                    }`}>
                      {order.status}
                    </span>
                    {order.status !== 'Delivered' && (
                       <span className="flex h-2 w-2 rounded-full bg-orange-500 animate-ping"></span>
                    )}
                  </div>
                  <p className="text-[10px] text-gray-400 font-bold uppercase mt-2 tracking-tighter">
                    ID: {order.id.slice(0, 8)} • {new Date(order.created_at).toLocaleDateString()} at {new Date(order.created_at).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                  </p>
                </div>
              </div>

              <div className="bg-gray-50 rounded-2xl p-4 space-y-3">
                {order.items.map((item, idx) => (
                  <div key={idx} className="flex justify-between items-center text-xs">
                    <div className="flex items-center space-x-2">
                      <span className="w-5 h-5 bg-white rounded-md flex items-center justify-center font-black text-orange-500 border border-gray-100">{item.quantity}</span>
                      <span className="text-gray-700 font-bold">{item.name}</span>
                    </div>
                    <span className="text-gray-400 font-medium">₹{item.price * item.quantity}</span>
                  </div>
                ))}

                <div className="pt-3 border-t border-gray-200 mt-2 flex justify-between items-center">
                   <div className="flex items-center text-[10px] font-black text-gray-400 uppercase tracking-widest">
                     <i className="fas fa-location-dot mr-1.5 text-orange-400"></i>
                     {order.location}
                   </div>
                   <div className="text-right">
                    <p className="text-lg font-black text-orange-600">₹{order.total_amount}</p>
                  </div>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default TrackingTab;
